				writeJSON(w, http.StatusForbidden, errResp{err.Error()})
				return
			}
		}

		timeout := time.Duration(req.TimeoutMs) * time.Millisecond
		result := executor.Run(req.Command, timeout)

		writeJSON(w, http.StatusOK, result)
	}
}

