func splitAndTrim(s string) []string {
	var result []string
	current := ""
	for _, c := range s {
		if c == ',' {
			result = append(result, trimSpaces(current))
			current = ""
		} else {
			current += string(c)
		}
	}
	result = append(result, trimSpaces(current))
	return result
